var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"결국...... 운명의 상대 같은 건...... 없던 거였나?","JPN":"結局……運命の相手なんて……いなかったのかな？","ENG":"So... There's no such thing as soul mates, is there?","TWN":"結果……命運之人什麼的……是不存在的嗎？"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그래...... 이런 게 내게 어울리는 결말이지.","JPN":"そう……これが私にぴったりの結末。","ENG":"Yes... This is such a fitting end for someone like me.","TWN":"也是……這才是最適合我的結局。"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하긴 악당에게 해피엔딩이라니..... 가당치도 않네.","JPN":"確かに悪党にハッピーエンドなんて……相応しくないか。","ENG":"Villains don't deserve a happy ending. What was I thinking?","TWN":"反派怎麼可能會有幸福結局呢……真是可笑。"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"겨우 찾았다고 생각했는데...... 어째서......","JPN":"やっと見つけたと思ったのに……どうして……","ENG":"I thought I'd finally found him... Why...","TWN":"本來以為終於找到了……為什麼……"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 그렇게 시무룩해져 있나, 누굴 잃기라도 한 것처럼.","JPN":"どうして、そんな暗い顔をしているんだ。大切な人でも失ったのか？","ENG":"Why are you so sullen? You look as if you've lost someone.","TWN":"妳為什麼要這麼難過，好像失去了什麼重要的人一樣。"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하, 이젠 환청까지 들리는 건가.","JPN":"はぁ、幻聴まで聞こえるなんて。","ENG":"Hah, now I'm even hearing things.","TWN":"唉，連幻聽都出現了。"},"stage":{"bg":"SUMMER_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이쪽일세.","JPN":"こっちだ。","ENG":"I'm here.","TWN":"我在這裡。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"서, 선배님?!","JPN":"せ、先輩！？","ENG":"D-Dark?","TWN":"前、前輩？！"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"무사한 것 같아서 다행이군, 후배님.","JPN":"無事で良かったよ。","ENG":"I'm glad you're safe, Lone.","TWN":"妳沒事真是太好了，後輩。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님? 살아계셨던 건가요? 대체 어떻게?","JPN":"先輩？　生きていたのですか？　いったいどうやって？","ENG":"Dark! You're alive! But how?","TWN":"前輩？你還活著？怎麼會？"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"거대 로봇에 설치해둔 탈출 장치가 성능이 너무 좋아서 말이지.","JPN":"巨大ロボットに設置しておいた脱出装置の性能が良くてな。","ENG":"My robot had a powerful ejector.","TWN":"我在巨大機器人裡安裝的逃命裝置性能實在太好了。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아주 멀리까지 날아가는 바람에 돌아오느라 시간이 좀 걸렸다네.","JPN":"遠くに飛ばされてしまい、戻ってくるのに少し時間がかかったのだ。","ENG":"I was sent so far away that it took me a long time to come back.","TWN":"飛得距離比我預想得還要遠，所以回來的時候花了一點時間。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"설마 이 불사신 머신갑 다크님께서 죽었다고 생각한 건 아니겠지?","JPN":"まさか、この不死身のマシーン-甲-ダークが死んだと思ったのか？","ENG":"You didn't think I, the immortal Machine G.A.P. Dark, was dead, did you?","TWN":"妳該不會以為我這不滅的機甲·皇級Type：黑暗大人就這麼死了吧？"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그, 그럴리가요......","JPN":"い、いえ！　そんな……","ENG":"O-of course not.","TWN":"怎、怎麼可能……"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"흐윽...... 그럴 리가...... 흐그극...... 없잖아요!","JPN":"うぅ……そんなわけ……ひっく……ないじゃないですか！","ENG":"*Sniffle* Absolutely... *Sniffle* Not!","TWN":"嗚……沒有……嗚嗚……真的沒有！"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"역시 날 믿어주는 건 후배님뿐이라니까.","JPN":"やはり私を信じてくれるのは後輩さんだけだ。","ENG":"I knew I could count on you, Lone.","TWN":"果然，就只有後輩會相信我。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그러니까 이제 울지 말게. 씩씩하고 악당답게, 웃으면서 살아가기로 약속하지 않았나?","JPN":"だから、もう泣くな。凜々しく、悪党らしく、笑顔で生きていくと約束してくれないか？","ENG":"Now, stop crying. You promised to me that you'd live happily like the spirited villainess you are.","TWN":"所以別再哭了。妳不是和我約好了，說要像個堅強反派一樣，笑著活下去嗎？"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네, 선배님.","JPN":"はい、先輩。","ENG":"Yes, Dark.","TWN":"是的，前輩。"},"stage":{"bg":"SUMMER_06","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};